+export function getLocalDevTokenEmail(token: string | undefined): string | null {
+  if (!token) return null;
+
+  const [headerB64, payloadB64, signature, extra] = token.split(".");
+  if (!headerB64 || !payloadB64 || !signature || extra !== undefined) {
+    return null;
+  }
+
+  const expectedSignature = createHmac("sha256", getLocalDevJwtSecret())
+    .update(`${headerB64}.${payloadB64}`)
+    .digest("base64url");
+
+  if (!signaturesMatch(signature, expectedSignature)) {
+    return null;
+  }
+
+  const header = decodeTokenPart(headerB64);
+  if (header?.alg !== "HS256" || header.typ !== "JWT") {
+    return null;
+  }
+
+  const payload = decodeTokenPart(payloadB64);
+  if (
+    payload?.iss !== LOCAL_DEV_ISSUER ||
+    payload.client_id !== LOCAL_DEV_CLIENT_ID ||
+    !isLocalDevTokenUse(payload.token_use) ||
+    typeof payload.email !== "string" ||
+    !payload.email.trim()
+  ) {
+    return null;
+  }
+
+  return payload.email;
+}
