 }
+
+function decodeTokenPart(part: string): Record<string, unknown> | null {
+  try {
+    const parsed: unknown = JSON.parse(
+      Buffer.from(part, "base64url").toString("utf8"),
+    );
+    return isRecord(parsed) ? parsed : null;
+  } catch {
+    return null;
+  }
+}
+
+function isRecord(value: unknown): value is Record<string, unknown> {
+  return typeof value === "object" && value !== null && !Array.isArray(value);
+}
+
+function isLocalDevTokenUse(value: unknown): value is LocalDevTokenUse {
+  return value === "access" || value === "id" || value === "refresh";
+}
+
+function signaturesMatch(signature: string, expectedSignature: string): boolean {
+  const actual = Buffer.from(signature);
+  const expected = Buffer.from(expectedSignature);
+  return actual.length === expected.length && timingSafeEqual(actual, expected);
+}
